 Double_t RooTimePdfBkg::evaluate() const 
 { 
   // ENTER EXPRESSION IN TERMS OF VARIABLE ARGUMENTS HERE 

  Double_t expT = fracT*alpha1T*exp(alpha1T*time)/(exp(alpha1T*time.max())-exp(alpha1T*time.min()))+
                  (1-fracT)*alpha2T*exp(alpha2T*time)/(exp(alpha2T*time.max())-exp(alpha2T*time.min()));
  Double_t expU = fracU*alpha1U*exp(alpha1U*time)/(exp(alpha1U*time.max())-exp(alpha1U*time.min()))+
                  (1-fracU)*alpha2U*exp(alpha2U*time)/(exp(alpha2U*time.max())-exp(alpha2U*time.min()));

//  Double_t accT = (1+erf(c1T*time+c2T));
//  Double_t accU = (1+erf(c1U*time+c2U));

//  Double_t accT = (1+erf(c1T-c1T*time));
//  Double_t accU = (1+erf(c1U-c1U*time));

  Double_t accT = (1+tanh(c1T-c1T*time));
  Double_t accU = (1+tanh(c1U-c1U*time));

  Double_t retVal = (q==0) ? accU*expU :
                             accT*expT;


  Int_t iq = q;
  Double_t dtime = time;
  Double_t dtimeMax = time.max();
  Double_t dtimeMin = time.min();
  //printf("EVALUATE %d %g %g %g %g\n",iq,dtime,dtimeMin,dtimeMax,retVal);
  return retVal;

 } 



